    def _execute(self, operation_name, payload):
        plan = operation_plan(operation_name, payload)
        result = {'ok': plan['ok'], 'pbc': 'multi_sided_market', 'operation': operation_name, 'operation_kind': plan.get('operation_kind'), 'payload': dict(payload), 'operation_contract': plan, 'transaction_boundary': plan.get('transaction_boundary'), 'side_effects': ()}
